#' Collate Primary Keys
#'
#' @description
#' Combines primary key information from _mighty.yml (via study@mighty) and ADaM
#' domain specifications. The _mighty.yml file contains keys for external datasets
#' (SDTM, metadata, and pre-existing ADaM). Domain specifications contain
#' keys for ADaM domains being generated by mighty.
#'
#' @param ui_yml List of ADaM domain specifications, each containing a `keys` element.
#' @param external_data List of external data definitions from study@mighty$external_data,
#'   where each element is a list with `id` (domain name) and `keys` (key variables).
#'
#' @return
#' A list where each element is a named vector containing the primary keys
#' for that domain, combining external_data from _mighty.yml and domain spec keys.
#' All domain names are converted to uppercase.
#'
#' @noRd
collate_primary_keys <- function(ui_yml, external_data) {
  adam_keys <- lapply(ui_yml, \(domain_spec) domain_spec$keys) |>
    stats::setNames(toupper(names(ui_yml)))

  keys <- convert_external_data_to_keys(external_data)

  if (is.null(keys)) {
    return(adam_keys)
  }

  # Check for domains specified in both places
  names(keys) <- toupper(names(keys))
  duplicates <- intersect(names(adam_keys), names(keys))
  if (length(duplicates) > 0) {
    dup_list <- format_list(duplicates, format_domain)
    dup_msg <- paste0("The following domains appear in both: ", dup_list)

    throw_validation_error(
      category = "Duplicate domain keys",
      details = c(
        "Domains have keys defined in both {.file _mighty.yml} and domain specifications",
        "x" = dup_msg,
        "i" = "ADaM domains generated by mighty should only have keys in domain specs, not {.file _mighty.yml}"
      ),
      suggestions = c(
        "Remove key definitions from {.file _mighty.yml} for ADaM domains",
        "Keep key definitions in domain specification files",
        "Use {.file _mighty.yml} {.field /external_data} only for external domains (SDTM, etc.)"
      )
    )
  }

  c(keys, adam_keys)
}

#' Convert external_data array-of-objects to named list
#'
#' @param external_data List of external data definitions, each with `id` and `keys`.
#' @return Named list mapping domain names to key variables, or `NULL` if input is `NULL`.
#' @noRd
convert_external_data_to_keys <- function(external_data) {
  if (is.null(external_data) || length(external_data) == 0) {
    return(NULL)
  }
  stats::setNames(
    lapply(external_data, \(x) x$keys),
    vapply(external_data, \(x) x$id, character(1))
  )
}
